--- crt1.c	Wed Sep  9 10:11:21 1998
+++ /tmp/crt1.c.new	Wed Dec  9 19:43:17 1998
@@ -72,8 +72,13 @@
     argc = * (int *) (argv - 1);
     env = argv + argc + 1;
     environ = env;
-    if(argc > 0)
+    if(argc > 0 && argv[0]) {
+	register char *s;
 	__progname = argv[0];
+	for (s = __progname; *s != '\0'; s++)
+		if (*s == '/')
+			__progname = s + 1;
+    }

     if(&_DYNAMIC != 0)
 	atexit(rtld_cleanup);
How-To-Repeat: 
	Simple program test.c:

		#include <stdio.h>
		extern char *__progname;
		int main(void)
		{
			printf("%s\n", __progname);
			return 0;
		}

	gives there results:

	# gcc -aout -o test test.c
	# ./././test
	test
	# gcc -elf -o test test.c
	# ./././test
	./././test
